var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_NULL","text":{"KOREA":"생각이 담긴 발걸음, 떨리는 숨소리, 기다리는 이를 배려하여 조심스럽게 문을 여는 소리…….","JPN":"思いが込められた足取り、震える息づかい、自分を待つ人に配慮し控えめに扉を開く音……","ENG":"The sound of footsteps lost in thought, the shaking breaths, and the cautious opening of a door so as not to startle the one waiting inside...","TWN":"若有所思的步伐，急促的呼吸聲，顧慮到等候的人而輕聲開門……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_NULL","text":{"KOREA":"오셨군요, 관리자님.","JPN":"おいでになりましたね、管理者様。","ENG":"You’re here, Administrator.","TWN":"管理者，你來啦。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_NULL","text":{"KOREA":"신부 네퀴티아, 인사드립니다.","JPN":"花嫁ネキティア、ご挨拶申し上げます。","ENG":"Your bride Nequitia, pleased to see you.","TWN":"你好，我是新娘莉奎蒂亞。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_NULL","text":{"KOREA":"후훗. 당황하셨나 보군요. 제게도 이런 면이 있다는 사실이 그만큼 놀라우셨을까요?","JPN":"ふふっ。慌てているようですね。私にもこのような一面があるということがそんなに意外でしたか？","ENG":"Fu Fuu. You seem startled. Was it that shocking to see a different part of myself?","TWN":"呵呵，你有點不知所措呢，沒想到我也有這一面吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_NULL","text":{"KOREA":"단원들은 모두 물렸습니다. 여러 소리가 섞이니 지저분해져서요.","JPN":"団員はみんな帰しました。色んな音が混ざると汚くなりますので。","ENG":"I’ve dismissed all members. It became too disorganized with all the different noises.","TWN":"我已經將團員們都支開，因為各種聲音參雜在一起會很混亂。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_NULL","text":{"KOREA":"단 하나의 악기만으로도 최상의 공연을 이끌어낼 수 있는 건 오로지 지휘자의 능력에 따른 일이죠.","JPN":"たった一つの楽器だけで最高の公演に作り上げられるかどうかは、すべて指揮者の能力にかかっています。","ENG":"Bringing forth the finest of performances even with just one instrument... It depends entirely on the conductor’s abilities.","TWN":"一個優秀的指揮家，只用一種樂器就能夠呈現出最棒的演出。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_NULL","text":{"KOREA":"관리자님께서는… 악기의 역할보다 지휘자의 역할이 더 잘 어울리시는 듯 하지만요.","JPN":"管理者様は……楽器より指揮者の役割の方がもっと合いそうな気がしますが。","ENG":"But you, Administrator... You seem better fitted to the role of the conductor rather than an instrument.","TWN":"不過管理者你…比起樂器，更適合擔任指揮家的角色。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_NULL","text":{"KOREA":"당신께서 꿈꾸시는 우리 둘의 하모니가 어떤 템포로 향해 갈지는 모르겠으나……","JPN":"あなたが夢見る私たち二人のハーモニーがどのようなテンポとなるかはわかりませんが……","ENG":"I know not to which tempo the harmony we create will lead...","TWN":"雖然我不清楚在你的夢想中，我們的協奏曲會是什麼樣的節奏……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_NULL","text":{"KOREA":"제가 기꺼이 당신이 만들 하모니에 동참하리란 것이 확실하니, 그렇게까지 떨려하실 필요는 없습니다.","JPN":"私はあなたの作り出すハーモニーならば喜んでご一緒します。ですから、そこまで緊張する必要はありません。","ENG":"But I do know that I’ll always be happy to harmonize with you, so you mustn’t be so concerned.","TWN":"但可以確定的是，我很樂意加入你將要演奏出的協奏曲當中，你不需要如此緊張。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_NULL","text":{"KOREA":"제게… 가까이 와 주시겠어요?","JPN":"私の……近くまで来てくれますか？","ENG":"Would you... come a little closer to me?","TWN":"你可以…再靠近我一點嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};